import {
  ExceptionFilter,
  Catch,
  ArgumentsHost,
  HttpException,
  HttpStatus,
  Logger,
} from '@nestjs/common';
import { Request, Response } from 'express';

@Catch()
export class GlobalExceptionFilter implements ExceptionFilter {
  private readonly logger = new Logger(GlobalExceptionFilter.name);

  catch(exception: unknown, host: ArgumentsHost) {
    const ctx = host.switchToHttp();
    const response = ctx.getResponse<Response>();
    const request = ctx.getRequest<Request>();

    let status = HttpStatus.INTERNAL_SERVER_ERROR;
    let message = 'Internal server error';

    if (exception instanceof HttpException) {
      status = exception.getStatus();
      const exceptionResponse = exception.getResponse();

      // Handle class-validator messages which might be an array
      if (
        typeof exceptionResponse === 'object' &&
        exceptionResponse !== null &&
        'message' in exceptionResponse
      ) {
        const msg = (exceptionResponse as any).message;
        message = Array.isArray(msg) ? msg.join(', ') : msg;
      } else {
        message = exception.message || 'Error occurred';
      }
    } else if (exception instanceof Error) {
      status = (exception as any).status || HttpStatus.INTERNAL_SERVER_ERROR;
      message = exception.message;
      // Log the full stack trace for internal server errors
      if (status === HttpStatus.INTERNAL_SERVER_ERROR) {
        this.logger.error(
          `Error processing request for ${request.url}: ${exception.stack}`,
        );
      }
    } else {
      this.logger.error(
        `Unknown error processing request for ${request.url}: ${JSON.stringify(exception)}`,
      );
    }

    // Format the standard response structure
    response.status(status).json({
      code: status,
      message: message,
      data: null,
      path: request.url,
      timestamp: new Date().toISOString(),
    });
  }
}

import { Test, TestingModule } from '@nestjs/testing';
import { AiChatService } from './ai-chat.service';
import { getRepositoryToken } from '@nestjs/typeorm';
import { AiChatSession } from '../../entities/ai-chat-session.entity';
import { AiChatMessage } from '../../entities/ai-chat-message.entity';
import { SettingsService } from '../settings/settings.service';
import { AiService } from './ai.service';
import { BadRequestException, NotFoundException } from '@nestjs/common';

jest.mock('@google/generative-ai');

describe('AiChatService', () => {
  let service: AiChatService;
  let sessionRepo: any;
  let messageRepo: any;
  let settingsService: any;
  let aiService: any;

  beforeEach(async () => {
    sessionRepo = {
      findOne: jest.fn(),
      create: jest.fn().mockImplementation((dto) => dto),
      save: jest
        .fn()
        .mockImplementation((dto) => ({ ...dto, id: 'session-1' })),
      find: jest.fn(),
      remove: jest.fn(),
    };

    messageRepo = {
      create: jest.fn().mockImplementation((dto) => dto),
      save: jest.fn().mockImplementation((dto) => ({ ...dto, id: 'msg-1' })),
      find: jest.fn().mockResolvedValue([]),
    };

    settingsService = {
      getAll: jest.fn().mockResolvedValue({
        'ai.chatApiKey': 'test-key',
        'ai.chatModel': 'gemini-test',
      }),
    };

    aiService = {
      createTask: jest.fn(),
    };

    const module: TestingModule = await Test.createTestingModule({
      providers: [
        AiChatService,
        {
          provide: getRepositoryToken(AiChatSession),
          useValue: sessionRepo,
        },
        {
          provide: getRepositoryToken(AiChatMessage),
          useValue: messageRepo,
        },
        {
          provide: SettingsService,
          useValue: settingsService,
        },
        {
          provide: AiService,
          useValue: aiService,
        },
      ],
    }).compile();

    service = module.get<AiChatService>(AiChatService);
  });

  afterEach(() => {
    jest.clearAllMocks();
  });

  describe('listSessions', () => {
    it('should return user sessions', async () => {
      sessionRepo.find.mockResolvedValue([{ id: 'session-1' }]);
      const sessions = await service.listSessions(1);
      expect(sessions).toEqual([{ id: 'session-1' }]);
      expect(sessionRepo.find).toHaveBeenCalledWith(
        expect.objectContaining({ where: { userId: 1 } }),
      );
    });
  });

  describe('getSession', () => {
    it('should return session and messages', async () => {
      sessionRepo.findOne.mockResolvedValue({ id: 'session-1' });
      messageRepo.find.mockResolvedValue([{ id: 'msg-1', content: 'hello' }]);

      const result = await service.getSession('session-1', 1);
      expect(result.id).toBe('session-1');
      expect(result.messages).toHaveLength(1);
    });

    it('should throw if session not found', async () => {
      sessionRepo.findOne.mockResolvedValue(null);
      await expect(service.getSession('nonexistent', 1)).rejects.toThrow(
        BadRequestException,
      );
    });
  });

  describe('deleteSession', () => {
    it('should delete session', async () => {
      sessionRepo.findOne.mockResolvedValue({ id: 'session-1' });
      await service.deleteSession('session-1', 1);
      expect(sessionRepo.remove).toHaveBeenCalled();
    });
  });

  describe('injectMessage', () => {
    it('should inject a message and update session', async () => {
      const session = { id: 'session-1', updatedAt: new Date() };
      sessionRepo.findOne.mockResolvedValue(session);

      await service.injectMessage('session-1', 1, 'system', 'test msg');

      expect(sessionRepo.save).toHaveBeenCalledWith(
        expect.objectContaining({ id: 'session-1' }),
      );
      expect(messageRepo.save).toHaveBeenCalledWith(
        expect.objectContaining({
          role: 'system',
          content: 'test msg',
        }),
      );
    });

    it('should throw NotFoundException if session not found', async () => {
      sessionRepo.findOne.mockResolvedValue(null);
      await expect(
        service.injectMessage('session-1', 1, 'system', 'test msg'),
      ).rejects.toThrow(NotFoundException);
    });
  });
});

import { Test, TestingModule } from '@nestjs/testing';
import { AiController } from './ai.controller';
import { AiService } from './ai.service';
import { AiChatService } from './ai-chat.service';
import { AuditService } from '../audit/audit.service';
import { getRepositoryToken } from '@nestjs/typeorm';
import { User } from '../../entities/user.entity';

describe('AiController', () => {
  let controller: AiController;
  let aiService: AiService;
  let aiChatService: AiChatService;
  let auditService: AuditService;

  beforeEach(async () => {
    const module: TestingModule = await Test.createTestingModule({
      controllers: [AiController],
      providers: [
        {
          provide: AiService,
          useValue: {
            workerHealth: jest.fn(),
            getTemplates: jest.fn(),
            getUploadUrl: jest.fn(),
            createTask: jest.fn(),
            listTasks: jest.fn(),
            getTask: jest.fn(),
            cancelTask: jest.fn(),
            deleteTask: jest.fn(),
            resumeTask: jest.fn(),
            getTaskFiles: jest.fn(),
            getDirectDownloadUrl: jest.fn(),
            proxyDownload: jest.fn(),
            proxyLogStream: jest.fn(),
          },
        },
        {
          provide: AiChatService,
          useValue: {
            chatStream: jest.fn(),
            listSessions: jest.fn(),
            getSession: jest.fn(),
            injectMessage: jest.fn(),
            deleteSession: jest.fn(),
          },
        },
        {
          provide: AuditService,
          useValue: {
            log: jest.fn(),
          },
        },
        {
          provide: getRepositoryToken(User),
          useValue: {
            find: jest.fn(),
          },
        },
      ],
    }).compile();

    controller = module.get<AiController>(AiController);
    aiService = module.get<AiService>(AiService);
    aiChatService = module.get<AiChatService>(AiChatService);
    auditService = module.get<AuditService>(AuditService);
  });

  describe('createTask', () => {
    it('should create a task and log audit', async () => {
      const mockUser = { id: 1, username: 'testuser' };
      const req = { user: mockUser, ip: '127.0.0.1' } as any;
      const body = { type: 'test-type', params: {} };

      (aiService.createTask as jest.Mock).mockResolvedValue({
        code: 0,
        data: { id: 'task-1' },
      });

      const result = await controller.createTask(body, req);

      expect(result.code).toBe(0);
      expect(aiService.createTask).toHaveBeenCalledWith(body, 1);
      expect(auditService.log).toHaveBeenCalled();
    });
  });

  describe('listTasks', () => {
    it('should list tasks for current user', async () => {
      const mockUser = { id: 1, role: { name: 'user' } };
      const req = { user: mockUser } as any;

      (aiService.listTasks as jest.Mock).mockResolvedValue({
        code: 0,
        data: [],
      });

      const result = await controller.listTasks(req, '1', '10');

      expect(result.code).toBe(0);
      expect(aiService.listTasks).toHaveBeenCalledWith({
        page: 1,
        limit: 10,
        userId: 1,
      });
    });
  });

  describe('chatSessions', () => {
    it('should return user chat sessions', async () => {
      const mockUser = { id: 1 };
      const req = { user: mockUser } as any;

      (aiChatService.listSessions as jest.Mock).mockResolvedValue([]);

      const result = await controller.chatSessions(req);

      expect(result.code).toBe(0);
      expect(result.data).toEqual([]);
      expect(aiChatService.listSessions).toHaveBeenCalledWith(1);
    });
  });
});

import { Test, TestingModule } from '@nestjs/testing';
import { AiService } from './ai.service';
import { ConfigService } from '@nestjs/config';
import { FilesService } from '../files/files.service';
import axios from 'axios';
import { NotFoundException, ServiceUnavailableException } from '@nestjs/common';

jest.mock('axios');

describe('AiService', () => {
  let service: AiService;
  let mockAxiosInstance: any;

  beforeEach(async () => {
    mockAxiosInstance = {
      get: jest.fn(),
      post: jest.fn(),
      delete: jest.fn(),
    };
    (axios.create as jest.Mock).mockReturnValue(mockAxiosInstance);

    const module: TestingModule = await Test.createTestingModule({
      providers: [
        AiService,
        {
          provide: ConfigService,
          useValue: {
            get: jest
              .fn()
              .mockImplementation(
                (key: string, defaultValue: any) => defaultValue,
              ),
          },
        },
        {
          provide: FilesService,
          useValue: {},
        },
      ],
    }).compile();

    service = module.get<AiService>(AiService);
  });

  afterEach(() => {
    jest.clearAllMocks();
  });

  describe('createTask', () => {
    it('should successfully post a task', async () => {
      const dto = { type: 'test', params: {} };
      mockAxiosInstance.post.mockResolvedValue({ data: { id: 'task-1' } });
      const result = await service.createTask(dto, 1);
      expect(result).toEqual({ id: 'task-1' });
      expect(mockAxiosInstance.post).toHaveBeenCalledWith('/api/tasks', {
        ...dto,
        userId: 1,
      });
    });

    it('should throw ServiceUnavailableException on network error', async () => {
      mockAxiosInstance.post.mockRejectedValue({
        code: 'ECONNREFUSED',
        message: 'Connection refused',
      });
      await expect(
        service.createTask({ type: 'test', params: {} }, 1),
      ).rejects.toThrow(ServiceUnavailableException);
    });
  });

  describe('getTask', () => {
    it('should return task data', async () => {
      mockAxiosInstance.get.mockResolvedValue({ data: { id: 'task-1' } });
      const result = await service.getTask('task-1');
      expect(result).toEqual({ id: 'task-1' });
    });

    it('should throw NotFoundException on 404', async () => {
      mockAxiosInstance.get.mockRejectedValue({ response: { status: 404 } });
      await expect(service.getTask('nonexistent')).rejects.toThrow(
        NotFoundException,
      );
    });
  });

  describe('deleteTask', () => {
    it('should delete task successfully', async () => {
      mockAxiosInstance.delete.mockResolvedValue({ data: { success: true } });
      const result = await service.deleteTask('task-1');
      expect(result).toEqual({ success: true });
    });
  });

  describe('getDirectDownloadUrl', () => {
    it('should extract correct file url', async () => {
      mockAxiosInstance.get.mockResolvedValue({
        data: [{ name: 'test.png', url: 'http://cos.url/test.png', size: 100 }],
      });
      const result = await service.getDirectDownloadUrl('task-1', 'test.png');
      expect(result.url).toBe('http://cos.url/test.png');
    });

    it('should throw NotFoundException if file not in list', async () => {
      mockAxiosInstance.get.mockResolvedValue({
        data: [
          { name: 'other.png', url: 'http://cos.url/other.png', size: 100 },
        ],
      });
      await expect(
        service.getDirectDownloadUrl('task-1', 'test.png'),
      ).rejects.toThrow(NotFoundException);
    });
  });
});

import { Test, TestingModule } from '@nestjs/testing';
import { AuditService } from './audit.service';
import { getRepositoryToken } from '@nestjs/typeorm';
import { AuditLog, AuditType } from '../../entities/audit-log.entity';
import { Setting } from '../../entities/setting.entity';

describe('AuditService', () => {
  let service: AuditService;
  let auditRepo: any;
  let settingRepo: any;

  beforeEach(async () => {
    const qbMock = {
      orderBy: jest.fn().mockReturnThis(),
      andWhere: jest.fn().mockReturnThis(),
      getCount: jest.fn().mockResolvedValue(10),
      offset: jest.fn().mockReturnThis(),
      limit: jest.fn().mockReturnThis(),
      getMany: jest.fn().mockResolvedValue([{ id: 1 }]),
      delete: jest.fn().mockReturnThis(),
      from: jest.fn().mockReturnThis(),
      execute: jest.fn(),
    };

    auditRepo = {
      create: jest.fn().mockImplementation((dto) => dto),
      save: jest.fn(),
      createQueryBuilder: jest.fn(() => qbMock),
    };

    settingRepo = {
      findOne: jest.fn(),
      find: jest.fn().mockResolvedValue([]),
      create: jest.fn().mockImplementation((dto) => dto),
      save: jest.fn(),
    };

    const module: TestingModule = await Test.createTestingModule({
      providers: [
        AuditService,
        { provide: getRepositoryToken(AuditLog), useValue: auditRepo },
        { provide: getRepositoryToken(Setting), useValue: settingRepo },
      ],
    }).compile();

    service = module.get<AuditService>(AuditService);
  });

  afterEach(() => {
    jest.clearAllMocks();
  });

  describe('log', () => {
    it('should log event if setting is not false', async () => {
      settingRepo.findOne.mockResolvedValue({ value: 'true' });
      await service.log({ type: AuditType.AI_TASK, action: 'test' });
      expect(auditRepo.create).toHaveBeenCalled();
      expect(auditRepo.save).toHaveBeenCalled();
    });

    it('should not log event if setting is false', async () => {
      settingRepo.findOne.mockResolvedValue({ value: 'false' });
      await service.log({ type: AuditType.AI_TASK, action: 'test' });
      expect(auditRepo.create).not.toHaveBeenCalled();
      expect(auditRepo.save).not.toHaveBeenCalled();
    });
  });

  describe('findAll', () => {
    it('should return paginated logs', async () => {
      const result = await service.findAll({ page: 1, pageSize: 10 });
      expect(result.items).toHaveLength(1);
      expect(result.total).toBe(10);
    });
  });

  describe('batchDelete', () => {
    it('should delete logs by criteria', async () => {
      const result = await service.batchDelete({ type: 'ai_task' });
      expect(result.deleted).toBe(10);
      expect(auditRepo.createQueryBuilder().execute).toHaveBeenCalled();
    });
  });

  describe('updateSettings', () => {
    it('should save settings properly', async () => {
      settingRepo.findOne.mockResolvedValue(null);
      await service.updateSettings({ ai_task: false });
      expect(settingRepo.save).toHaveBeenCalledWith(
        expect.objectContaining({
          key: 'audit.ai_task',
          value: 'false',
        }),
      );
    });
  });
});

import { Test, TestingModule } from '@nestjs/testing';
import { AuthController } from './auth.controller';
import { AuthService } from './auth.service';
import { AuditService } from '../audit/audit.service';
import { HttpStatus } from '@nestjs/common';
import * as express from 'express';

type MockService = Record<string, jest.Mock>;
type MockResponse = express.Response & {
  cookie: jest.Mock;
  clearCookie: jest.Mock;
  status: jest.Mock;
  json: jest.Mock;
};
type MockRequest = express.Request & {
  cookies?: Record<string, string>;
  user?: unknown;
};

describe('AuthController', () => {
  let controller: AuthController;
  let mockAuthService: MockService;
  let mockAuditService: MockService;
  let mockRes: MockResponse;
  let mockReq: MockRequest;

  beforeEach(async () => {
    mockAuthService = {
      register: jest.fn(),
      login: jest.fn(),
      refreshToken: jest.fn(),
      externalLogin: jest.fn(),
      bbsExternalLogin: jest.fn(),
    };

    mockAuditService = {
      log: jest.fn().mockResolvedValue(undefined),
    };

    mockRes = {
      cookie: jest.fn(),
      clearCookie: jest.fn(),
      status: jest.fn().mockReturnThis(),
      json: jest.fn((data) => data),
    } as unknown as MockResponse;

    mockReq = {
      ip: '127.0.0.1',
      headers: {},
      secure: false,
    } as MockRequest;

    const module: TestingModule = await Test.createTestingModule({
      controllers: [AuthController],
      providers: [
        { provide: AuthService, useValue: mockAuthService },
        { provide: AuditService, useValue: mockAuditService },
      ],
    }).compile();

    controller = module.get<AuthController>(AuthController);
  });

  afterEach(() => {
    jest.clearAllMocks();
  });

  it('should be defined', () => {
    expect(controller).toBeDefined();
  });

  describe('register', () => {
    it('should register a user', async () => {
      const registerDto = {
        username: 'test',
        password: 'password',
        role: 'user',
      };
      const resultData = {
        accessToken: 'token',
        refreshToken: 'refresh',
        user: { id: 1 },
      };
      mockAuthService.register.mockResolvedValue(resultData);

      const result = await controller.register(registerDto, mockReq, mockRes);

      expect(mockAuthService.register).toHaveBeenCalledWith(registerDto);
      expect(mockRes.cookie).toHaveBeenCalledWith(
        'refreshToken',
        'refresh',
        expect.any(Object),
      );
      expect(result).toEqual({
        code: 0,
        message: '注册成功',
        data: { accessToken: 'token', user: { id: 1 } },
      });
    });
  });

  describe('login', () => {
    it('should login a user and log audit', async () => {
      const loginDto = { username: 'test', password: 'password' };
      const resultData = {
        accessToken: 'token',
        refreshToken: 'refresh',
        user: { id: 1, username: 'test' },
      };
      mockAuthService.login.mockResolvedValue(resultData);

      const result = await controller.login(loginDto, mockReq, mockRes);

      expect(mockAuthService.login).toHaveBeenCalledWith(loginDto);
      expect(mockAuditService.log).toHaveBeenCalled();
      expect(mockRes.cookie).toHaveBeenCalled();
      expect(result).toEqual({
        code: 0,
        message: '登录成功',
        data: { accessToken: 'token', user: { id: 1, username: 'test' } },
      });
    });

    it('should throw error and log audit on failure', async () => {
      const loginDto = { username: 'test', password: 'password' };
      mockAuthService.login.mockRejectedValue(new Error('Invalid password'));

      await expect(
        controller.login(loginDto, mockReq, mockRes),
      ).rejects.toThrow('Invalid password');
      expect(mockAuditService.log).toHaveBeenCalledWith(
        expect.objectContaining({
          action: 'login_failed',
        }),
      );
    });
  });

  describe('refresh', () => {
    it('should return 401 if no refresh token', async () => {
      const reqWithoutCookie = { cookies: {} } as MockRequest;
      const result = await controller.refresh(reqWithoutCookie, mockRes);
      expect(mockRes.status).toHaveBeenCalledWith(HttpStatus.UNAUTHORIZED);
      expect(result).toEqual({ code: -1, message: '请重新登录' });
    });

    it('should refresh token successfully', async () => {
      const reqWithCookie = {
        cookies: { refreshToken: 'oldRefresh' },
        secure: false,
      } as MockRequest;
      const resultData = {
        accessToken: 'newToken',
        refreshToken: 'newRefresh',
        user: { id: 1 },
      };
      mockAuthService.refreshToken.mockResolvedValue(resultData);

      const result = await controller.refresh(reqWithCookie, mockRes);

      expect(mockAuthService.refreshToken).toHaveBeenCalledWith('oldRefresh');
      expect(mockRes.cookie).toHaveBeenCalledWith(
        'refreshToken',
        'newRefresh',
        expect.any(Object),
      );
      expect(result).toEqual({
        code: 0,
        message: '刷新成功',
        data: { accessToken: 'newToken', user: { id: 1 } },
      });
    });
  });

  describe('logout', () => {
    it('should clear cookie and return success', () => {
      const result = controller.logout(mockRes);
      expect(mockRes.clearCookie).toHaveBeenCalledWith(
        'refreshToken',
        expect.any(Object),
      );
      expect(result).toEqual({ code: 0, message: '退出成功' });
    });
  });

  describe('getProfile', () => {
    it('should return user profile', () => {
      const reqWithUser = {
        user: { id: 1, username: 'test' },
      } as MockRequest;
      const result = controller.getProfile(reqWithUser);
      expect(result).toEqual({ code: 0, data: { id: 1, username: 'test' } });
    });
  });

  describe('externalLogin', () => {
    it('should return error if missing params', async () => {
      const result = await controller.externalLogin(
        { ticketToken: '', nickname: '' },
        mockReq,
      );
      expect(result).toEqual({ code: -1, message: '缺少 token 或昵称参数' });
    });

    it('should perform external login', async () => {
      const data = { user: { ticketId: 123 } };
      mockAuthService.externalLogin.mockResolvedValue(data);

      const result = await controller.externalLogin(
        { ticketToken: 'abc', nickname: 'Guest' },
        mockReq,
      );

      expect(mockAuthService.externalLogin).toHaveBeenCalledWith(
        'abc',
        'Guest',
      );
      expect(mockAuditService.log).toHaveBeenCalledWith(
        expect.objectContaining({ action: 'external_login' }),
      );
      expect(result).toEqual({ code: 0, message: '临时接入成功', data });
    });
  });

  describe('bbsExternalLogin', () => {
    it('should return error if missing token', async () => {
      const result = await controller.bbsExternalLogin({ token: '' }, mockReq);
      expect(result).toEqual({ code: -1, message: '缺少 token 参数' });
    });

    it('should perform bbs external login', async () => {
      const data = { user: { bbsId: 456 } };
      mockAuthService.bbsExternalLogin.mockResolvedValue(data);

      const result = await controller.bbsExternalLogin(
        { token: 'xyz' },
        mockReq,
      );

      expect(mockAuthService.bbsExternalLogin).toHaveBeenCalledWith('xyz');
      expect(mockAuditService.log).toHaveBeenCalledWith(
        expect.objectContaining({ action: 'external_login' }),
      );
      expect(result).toEqual({ code: 0, message: '临时接入 BBS 成功', data });
    });
  });
});

import {
  Controller,
  Post,
  Body,
  Res,
  Req,
  HttpCode,
  HttpStatus,
  Get,
  UseGuards,
} from '@nestjs/common';
import { AuthService } from './auth.service';
import { RegisterDto, LoginDto } from './dto/auth.dto';
import { AuthGuard } from '@nestjs/passport';
import { AuditService } from '../audit/audit.service';
import { AuditType } from '../../entities/audit-log.entity';
import * as express from 'express';

@Controller('auth')
export class AuthController {
  constructor(
    private readonly authService: AuthService,
    private readonly auditService: AuditService,
  ) {}

  @Post('register')
  async register(
    @Body() registerDto: RegisterDto,
    @Req() req: express.Request,
    @Res() res: express.Response,
  ) {
    const result = await this.authService.register(registerDto);

    res.cookie('refreshToken', result.refreshToken, {
      httpOnly: true,
      secure: process.env.NODE_ENV === 'production' && req.secure,
      sameSite: 'lax',
      maxAge: 7 * 24 * 60 * 60 * 1000,
      path: '/api/auth',
    });

    return res.json({
      code: 0,
      message: '注册成功',
      data: {
        accessToken: result.accessToken,
        user: result.user,
      },
    });
  }

  @Post('login')
  @HttpCode(HttpStatus.OK)
  async login(
    @Body() loginDto: LoginDto,
    @Req() req: express.Request,
    @Res() res: express.Response,
  ) {
    const ip =
      (req.headers['x-forwarded-for'] as string) ||
      req.ip ||
      req.socket?.remoteAddress ||
      null;
    try {
      const result = await this.authService.login(loginDto);

      // 审计：登录成功
      void this.auditService.log({
        type: AuditType.USER_LOGIN,
        action: 'login',
        userId: result.user.id,
        username: result.user.username,
        detail: `用户 ${result.user.realName || result.user.username} 登录成功`,
        ip,
      });

      res.cookie('refreshToken', result.refreshToken, {
        httpOnly: true,
        secure: process.env.NODE_ENV === 'production' && req.secure,
        sameSite: 'lax',
        maxAge: 7 * 24 * 60 * 60 * 1000,
        path: '/api/auth',
      });

      return res.json({
        code: 0,
        message: '登录成功',
        data: {
          accessToken: result.accessToken,
          user: result.user,
        },
      });
    } catch (err: unknown) {
      const errMsg = err instanceof Error ? err.message : '密码错误';
      void this.auditService.log({
        type: AuditType.USER_LOGIN,
        action: 'login_failed',
        username: loginDto.username,
        detail: `用户 ${loginDto.username} 登录失败: ${errMsg}`,
        ip,
      });
      throw err;
    }
  }

  @Post('refresh')
  @HttpCode(HttpStatus.OK)
  async refresh(@Req() req: express.Request, @Res() res: express.Response) {
    const refreshToken = (
      req as express.Request & { cookies?: Record<string, string> }
    ).cookies?.refreshToken;
    if (!refreshToken) {
      return res.status(HttpStatus.UNAUTHORIZED).json({
        code: -1,
        message: '请重新登录',
      });
    }

    const result = await this.authService.refreshToken(refreshToken);

    res.cookie('refreshToken', result.refreshToken, {
      httpOnly: true,
      secure: process.env.NODE_ENV === 'production' && req.secure,
      sameSite: 'lax',
      maxAge: 7 * 24 * 60 * 60 * 1000,
      path: '/api/auth',
    });

    return res.json({
      code: 0,
      message: '刷新成功',
      data: {
        accessToken: result.accessToken,
        user: result.user,
      },
    });
  }

  @Post('logout')
  @HttpCode(HttpStatus.OK)
  logout(@Res() res: express.Response) {
    res.clearCookie('refreshToken', { path: '/api/auth' });
    return res.json({ code: 0, message: '退出成功' });
  }

  @Get('me')
  @UseGuards(AuthGuard('jwt'))
  getProfile(@Req() req: express.Request) {
    return { code: 0, data: (req as express.Request & { user: unknown }).user };
  }

  @Post('external/login')
  async externalLogin(
    @Body() body: { ticketToken: string; nickname: string },
    @Req() req: express.Request,
  ) {
    if (!body.ticketToken || !body.nickname) {
      return { code: -1, message: '缺少 token 或昵称参数' };
    }
    const ip =
      (req.headers['x-forwarded-for'] as string) ||
      req.ip ||
      req.socket?.remoteAddress ||
      null;
    const data = await this.authService.externalLogin(
      body.ticketToken,
      body.nickname,
    );

    // 审计：外部用户登录
    void this.auditService.log({
      type: AuditType.EXTERNAL_LOGIN,
      action: 'external_login',
      username: body.nickname,
      targetId: data.user?.ticketId || null,
      detail: `外部用户「${body.nickname}」通过共享链接接入工单`,
      ip,
    });

    return { code: 0, message: '临时接入成功', data };
  }

  @Post('external/bbs-login')
  async bbsExternalLogin(
    @Body() body: { token: string },
    @Req() req: express.Request,
  ) {
    if (!body.token) {
      return { code: -1, message: '缺少 token 参数' };
    }
    const ip =
      (req.headers['x-forwarded-for'] as string) ||
      req.ip ||
      req.socket?.remoteAddress ||
      null;
    const data = await this.authService.bbsExternalLogin(body.token);

    void this.auditService.log({
      type: AuditType.EXTERNAL_LOGIN,
      action: 'external_login',
      username: '匿名访客',
      targetId: data.user?.bbsId || null,
      detail: `外部访客通过免密链接匿名接入 BBS 帖子 #${data.user?.bbsId}`,
      ip,
    });

    return { code: 0, message: '临时接入 BBS 成功', data };
  }
}

import { Test, TestingModule } from '@nestjs/testing';
import { AuthService } from './auth.service';
import { JwtService } from '@nestjs/jwt';
import { ConfigService } from '@nestjs/config';
import { getRepositoryToken } from '@nestjs/typeorm';
import { User } from '../../entities/user.entity';
import { Role } from '../../entities/role.entity';
import { UnauthorizedException } from '@nestjs/common';
import * as bcrypt from 'bcryptjs';

type MockRepository = Record<string, jest.Mock>;
type MockJwtService = {
  sign: jest.Mock;
  verify: jest.Mock;
};
type MockConfigService = {
  get: jest.Mock;
};

describe('AuthService', () => {
  let service: AuthService;
  let mockUserRepo: MockRepository;
  let mockRoleRepo: MockRepository;
  let mockJwtService: MockJwtService;
  let mockConfigService: MockConfigService;

  const mockUser: Partial<User> = {
    id: 1,
    username: 'testuser',
    password: '', // Will be set in beforeEach
    displayName: 'Test User',
    realName: '测试用户',
    isActive: true,
    role: {
      id: 1,
      name: 'tech',
      description: '技术支持',
      permissions: [],
    } as Role,
  };

  beforeEach(async () => {
    mockUser.password = await bcrypt.hash('correct_password', 10);

    mockUserRepo = {
      findOne: jest.fn(),
      create: jest.fn(),
      save: jest.fn(),
    };

    mockRoleRepo = {
      findOne: jest.fn(),
      create: jest.fn(),
      save: jest.fn(),
    };

    mockJwtService = {
      sign: jest.fn().mockReturnValue('mocked_jwt_token'),
      verify: jest.fn(),
    };

    mockConfigService = {
      get: jest.fn((key: string) => {
        const config: Record<string, string> = {
          JWT_SECRET: 'test-secret',
          JWT_REFRESH_SECRET: 'test-refresh-secret',
          JWT_EXPIRES_IN: '15m',
          JWT_REFRESH_EXPIRES_IN: '7d',
        };
        return config[key];
      }),
    };

    const module: TestingModule = await Test.createTestingModule({
      providers: [
        AuthService,
        { provide: getRepositoryToken(User), useValue: mockUserRepo },
        { provide: getRepositoryToken(Role), useValue: mockRoleRepo },
        { provide: JwtService, useValue: mockJwtService },
        { provide: ConfigService, useValue: mockConfigService },
      ],
    }).compile();

    service = module.get<AuthService>(AuthService);
  });

  describe('login', () => {
    it('should return tokens for valid credentials', async () => {
      mockUserRepo.findOne.mockResolvedValue(mockUser);

      const result = await service.login({
        username: 'testuser',
        password: 'correct_password',
      });

      expect(result).toHaveProperty('accessToken');
      expect(result).toHaveProperty('refreshToken');
      expect(result.user.username).toBe('testuser');
      expect(result.user.role?.name).toBe('tech');
    });

    it('should throw UnauthorizedException for wrong password', async () => {
      mockUserRepo.findOne.mockResolvedValue(mockUser);

      await expect(
        service.login({ username: 'testuser', password: 'wrong_password' }),
      ).rejects.toThrow(UnauthorizedException);
    });

    it('should throw UnauthorizedException for non-existent user', async () => {
      mockUserRepo.findOne.mockResolvedValue(null);

      await expect(
        service.login({ username: 'ghost', password: 'any' }),
      ).rejects.toThrow(UnauthorizedException);
    });

    it('should throw UnauthorizedException for disabled user', async () => {
      mockUserRepo.findOne.mockResolvedValue({ ...mockUser, isActive: false });

      await expect(
        service.login({ username: 'testuser', password: 'correct_password' }),
      ).rejects.toThrow(UnauthorizedException);
    });
  });

  describe('refreshToken', () => {
    it('should return new tokens for valid refresh token', async () => {
      mockJwtService.verify.mockReturnValue({ sub: 1 });
      mockUserRepo.findOne.mockResolvedValue(mockUser);

      const result = await service.refreshToken('valid_refresh_token');

      expect(result).toHaveProperty('accessToken');
      expect(result).toHaveProperty('refreshToken');
    });

    it('should throw UnauthorizedException for invalid refresh token', async () => {
      mockJwtService.verify.mockImplementation(() => {
        throw new Error('Invalid token');
      });

      await expect(service.refreshToken('invalid_token')).rejects.toThrow(
        UnauthorizedException,
      );
    });

    it('should throw UnauthorizedException if user is inactive', async () => {
      mockJwtService.verify.mockReturnValue({ sub: 1 });
      mockUserRepo.findOne.mockResolvedValue(null);

      await expect(service.refreshToken('valid_but_user_gone')).rejects.toThrow(
        UnauthorizedException,
      );
    });
  });

  describe('register', () => {
    it('should successfully register a new user and return tokens', async () => {
      mockUserRepo.findOne.mockResolvedValue(null);
      mockRoleRepo.findOne.mockResolvedValue({
        id: 2,
        name: 'user',
        permissions: [],
      });
      mockUserRepo.create.mockImplementation((dto) => dto);
      mockUserRepo.save.mockImplementation(async (user) => ({
        ...user,
        id: 2,
      }));

      const result = await service.register({
        username: 'newuser',
        password: 'password123',
        realName: 'New User',
      });

      expect(result).toHaveProperty('accessToken');
      expect(result).toHaveProperty('refreshToken');
      expect(mockUserRepo.create).toHaveBeenCalled();
      expect(mockUserRepo.save).toHaveBeenCalled();
    });

    it('should throw ConflictException if username already exists', async () => {
      mockUserRepo.findOne.mockResolvedValue(mockUser);

      await expect(
        service.register({ username: 'testuser', password: 'password123' }),
      ).rejects.toThrow('用户名已存在');
    });
  });

  describe('externalLogin', () => {
    it('should return tokens and external user profile for valid external ticket token', async () => {
      mockJwtService.verify.mockReturnValue({
        role: 'external',
        ticketId: 100,
      });

      const result = await service.externalLogin('valid_token', 'Guest User');

      expect(result).toHaveProperty('accessToken');
      expect(result.user.username).toBe('Guest User');
      expect(result.user.ticketId).toBe(100);
      expect(result.user.role?.name).toBe('external');
    });

    it('should throw UnauthorizedException for invalid external token', async () => {
      mockJwtService.verify.mockImplementation(() => {
        throw new Error('Invalid');
      });

      await expect(
        service.externalLogin('invalid_token', 'Guest User'),
      ).rejects.toThrow(UnauthorizedException);
    });
  });

  describe('bbsExternalLogin', () => {
    it('should return tokens and external user profile for valid BBS token', async () => {
      mockJwtService.verify.mockReturnValue({
        role: 'external_bbs',
        bbsId: 200,
      });

      const result = await service.bbsExternalLogin('valid_bbs_token');

      expect(result).toHaveProperty('accessToken');
      expect(result.user.username).toBe('匿名访客');
      expect(result.user.bbsId).toBe(200);
    });

    it('should throw UnauthorizedException if role is incorrect', async () => {
      mockJwtService.verify.mockReturnValue({ role: 'user', bbsId: 200 });

      await expect(
        service.bbsExternalLogin('wrong_role_token'),
      ).rejects.toThrow(UnauthorizedException);
    });
  });

  describe('validateUser', () => {
    it('should return user for valid active user id', async () => {
      mockUserRepo.findOne.mockResolvedValue(mockUser);

      const result = await service.validateUser(1);
      expect(result).toBeDefined();
      expect(result?.username).toBe('testuser');
    });

    it('should return null for non-existent user', async () => {
      mockUserRepo.findOne.mockResolvedValue(null);

      const result = await service.validateUser(999);
      expect(result).toBeNull();
    });
  });
});

import {
  Injectable,
  Logger,
  UnauthorizedException,
  ConflictException,
} from '@nestjs/common';
import { JwtService } from '@nestjs/jwt';
import { InjectRepository } from '@nestjs/typeorm';
import { Repository } from 'typeorm';
import * as bcrypt from 'bcryptjs';
import { User } from '../../entities/user.entity';
import { Role } from '../../entities/role.entity';
import { RegisterDto, LoginDto } from './dto/auth.dto';
import { ConfigService } from '@nestjs/config';

@Injectable()
export class AuthService {
  private readonly logger = new Logger(AuthService.name);

  constructor(
    @InjectRepository(User)
    private readonly userRepository: Repository<User>,
    @InjectRepository(Role)
    private readonly roleRepository: Repository<Role>,
    private readonly jwtService: JwtService,
    private readonly configService: ConfigService,
  ) {}

  async register(registerDto: RegisterDto) {
    const existing = await this.userRepository.findOne({
      where: { username: registerDto.username },
    });
    if (existing) {
      throw new ConflictException('用户名已存在');
    }

    const hashedPassword = await bcrypt.hash(registerDto.password, 10);

    // 获取默认用户角色 - 新注册用户默认为普通用户组
    let defaultRole = await this.roleRepository.findOne({
      where: { name: 'user' },
      relations: ['permissions'],
    });
    if (!defaultRole) {
      defaultRole = await this.roleRepository.save(
        this.roleRepository.create({ name: 'user', description: '普通用户' }),
      );
      defaultRole.permissions = [];
    }

    const user = this.userRepository.create({
      ...registerDto,
      password: hashedPassword,
      displayName:
        registerDto.displayName || registerDto.realName || registerDto.username,
      realName: registerDto.realName,
      roleId: defaultRole.id,
    });

    const savedUser = await this.userRepository.save(user);
    savedUser.role = defaultRole;
    return this.generateTokens(savedUser);
  }

  async login(loginDto: LoginDto) {
    const user = await this.userRepository.findOne({
      where: { username: loginDto.username },
      relations: ['role', 'role.permissions'],
    });

    if (!user) {
      throw new UnauthorizedException('用户名或密码错误');
    }

    const isPasswordValid = await bcrypt.compare(
      loginDto.password,
      user.password,
    );
    if (!isPasswordValid) {
      throw new UnauthorizedException('用户名或密码错误');
    }

    if (!user.isActive) {
      throw new UnauthorizedException('账号已被禁用');
    }

    return this.generateTokens(user);
  }

  async refreshToken(refreshToken: string) {
    try {
      const payload = this.jwtService.verify(refreshToken, {
        secret: this.configService.get('JWT_REFRESH_SECRET'),
      });

      const user = await this.userRepository.findOne({
        where: { id: payload.sub },
        relations: ['role', 'role.permissions'],
      });

      if (!user || !user.isActive) {
        throw new UnauthorizedException('无效的刷新令牌');
      }

      return this.generateTokens(user);
    } catch (err) {
      this.logger.warn(
        `Refresh token verification failed: ${err instanceof Error ? err.message : 'unknown'}`,
      );
      throw new UnauthorizedException('无效的刷新令牌');
    }
  }

  private generateTokens(user: User) {
    const payload = {
      sub: user.id,
      username: user.username,
      role: user.role?.name,
    };

    const accessToken = this.jwtService.sign(payload, {
      secret: this.configService.get('JWT_SECRET'),
      expiresIn: this.configService.get('JWT_EXPIRES_IN') || '15m',
    });

    const refreshToken = this.jwtService.sign(payload, {
      secret: this.configService.get('JWT_REFRESH_SECRET'),
      expiresIn: this.configService.get('JWT_REFRESH_EXPIRES_IN') || '7d',
    });

    return {
      accessToken,
      refreshToken,
      user: {
        id: user.id,
        username: user.username,
        displayName: user.displayName,
        realName: user.realName,
        email: user.email,
        avatar: user.avatar,
        role: user.role
          ? {
              id: user.role.id,
              name: user.role.name,
              permissions: user.role.permissions || [],
            }
          : null,
      },
    };
  }

  async externalLogin(ticketToken: string, nickname: string) {
    try {
      const invitePayload = this.jwtService.verify(ticketToken, {
        secret: this.configService.get('JWT_SECRET'),
      });

      if (
        !invitePayload ||
        invitePayload.role !== 'external' ||
        !invitePayload.ticketId
      ) {
        throw new UnauthorizedException('无效的外链 Token');
      }

      // 生成带自定义昵称的访问令牌
      const newPayload = {
        sub: `ext-${Date.now()}`,
        username: nickname,
        role: 'external',
        ticketId: invitePayload.ticketId,
      };

      const accessToken = this.jwtService.sign(newPayload, {
        secret: this.configService.get('JWT_SECRET'),
        expiresIn: '7d', // 给外部用的固定长时间免刷 token
      });

      return {
        accessToken,
        user: {
          id: -1,
          username: nickname,
          displayName: nickname,
          ticketId: invitePayload.ticketId,
          role: { id: -1, name: 'external' },
        },
      };
    } catch (err) {
      this.logger.warn(
        `External login token verification failed: ${err instanceof Error ? err.message : 'unknown'}`,
      );
      throw new UnauthorizedException('无效的外链 Token 或验证失败');
    }
  }

  async bbsExternalLogin(token: string) {
    try {
      const invitePayload = this.jwtService.verify(token, {
        secret: this.configService.get('JWT_SECRET'),
      });

      if (
        !invitePayload ||
        invitePayload.role !== 'external_bbs' ||
        !invitePayload.bbsId
      ) {
        throw new UnauthorizedException('无效的外链 Token');
      }

      // 生成带自定义信息的访问令牌
      const newPayload = {
        sub: `ext-bbs-${Date.now()}`,
        username: '匿名访客',
        role: 'external',
        bbsId: invitePayload.bbsId,
      };

      const accessToken = this.jwtService.sign(newPayload, {
        secret: this.configService.get('JWT_SECRET'),
        expiresIn: '7d', // 给外部用的固定长时间免刷 token
      });

      return {
        accessToken,
        user: {
          id: -1,
          username: '匿名访客',
          displayName: '匿名访客',
          bbsId: invitePayload.bbsId,
          role: { id: -1, name: 'external' },
        },
      };
    } catch (err) {
      this.logger.warn(
        `BBS external login token verification failed: ${err instanceof Error ? err.message : 'unknown'}`,
      );
      throw new UnauthorizedException('无效的外链 Token 或验证失败');
    }
  }

  async validateUser(userId: number): Promise<User | null> {
    return this.userRepository.findOne({
      where: { id: userId, isActive: true },
      relations: ['role', 'role.permissions'],
    });
  }
}

import { Injectable } from '@nestjs/common';
import { PassportStrategy } from '@nestjs/passport';
import { ExtractJwt, Strategy } from 'passport-jwt';
import { ConfigService } from '@nestjs/config';
import { AuthService } from './auth.service';
import { Request } from 'express';

@Injectable()
export class JwtStrategy extends PassportStrategy(Strategy) {
  constructor(
    private readonly configService: ConfigService,
    private readonly authService: AuthService,
  ) {
    const jwtSecret = configService.get<string>('JWT_SECRET');
    if (!jwtSecret) {
      throw new Error(
        '❌ 环境变量 JWT_SECRET 未配置！请在 .env 文件中设置 JWT_SECRET 后重新启动。',
      );
    }
    super({
      jwtFromRequest: ExtractJwt.fromExtractors([
        ExtractJwt.fromAuthHeaderAsBearerToken(),
        (request: Request) => {
          return request?.query?.token as string;
        },
      ]),
      ignoreExpiration: false,
      secretOrKey: jwtSecret,
    });
  }

  async validate(payload: any) {
    if (payload.role === 'external') {
      return {
        id: payload.sub,
        username: payload.username,
        displayName: payload.username,
        role: { id: -1, name: 'external', permissions: [] },
        ticketId: payload.ticketId,
        bbsId: payload.bbsId,
      };
    }

    const user = await this.authService.validateUser(payload.sub);
    if (!user) {
      return null;
    }
    return {
      id: user.id,
      username: user.username,
      displayName: user.displayName,
      realName: user.realName,
      role: user.role,
    };
  }
}

import { Injectable, CanActivate, ExecutionContext } from '@nestjs/common';
import { Reflector } from '@nestjs/core';
import { EXTERNAL_ACCESS_KEY, PERMISSIONS_KEY } from './permissions.decorator';

@Injectable()
export class PermissionsGuard implements CanActivate {
  constructor(private reflector: Reflector) {}

  canActivate(context: ExecutionContext): boolean {
    const targets = [context.getHandler(), context.getClass()];
    const requiredPermissions = this.reflector.getAllAndOverride<string[]>(
      PERMISSIONS_KEY,
      targets,
    );
    const externalAccess = this.reflector.getAllAndOverride<string[]>(
      EXTERNAL_ACCESS_KEY,
      targets,
    );

    const { user } = context.switchToHttp().getRequest();

    // 如果未设置 @Permissions 验证，默认允许（或你可以选择默认拦截，当前配合系统保持放行）
    if (!requiredPermissions) {
      if (this.isExternalUser(user)) {
        return Array.isArray(externalAccess) && externalAccess.length > 0;
      }
      return true;
    }

    // 如果没有 user 或其不包含 role，拒绝访问 (例外：external 临时通行证有自己的鉴别)
    if (!user || !user.role) {
      return false;
    }

    // 外部分享 token 只允许访问显式标记的详情类路由，避免 tickets:read/bbs:read 被列表和搜索复用。
    if (this.isExternalUser(user)) {
      return Array.isArray(externalAccess) && externalAccess.length > 0;
    }

    // ⭐ 超级管理员通行权
    // 仅基于角色判断，不依赖 username，避免被注册同名账户绕过
    if (user.role.name === 'admin') {
      return true;
    }

    const permissions = user.role.permissions || [];
    // 检查用户所拥有的所有权限记录里，是否有包含 Controller 定义在此方法上的 ANY 或 ALL 需求
    // 这里我们使用: 用户具有需要的任一权限即放行
    const hasPermission = requiredPermissions.some((requiredCode) =>
      permissions.some((p: any) => {
        const pCode = p.code || `${p.resource}:${p.action}`;
        return pCode === requiredCode;
      }),
    );

    return hasPermission;
  }

  private isExternalUser(user: any): boolean {
    return user?.role === 'external' || user?.role?.name === 'external';
  }
}

