import { Test, TestingModule } from '@nestjs/testing';
import { ChatService } from './chat.service';
import { getRepositoryToken } from '@nestjs/typeorm';
import { Message } from '../../entities/message.entity';
import { Ticket } from '../../entities/ticket.entity';
import { NotFoundException, ForbiddenException } from '@nestjs/common';

import { SearchService } from '../search/search.service';
import { FilesService } from '../files/files.service';

describe('ChatService', () => {
  let service: ChatService;
  let mockMessageRepo: any;
  let mockTicketRepo: any;

  beforeEach(async () => {
    mockMessageRepo = {
      create: jest.fn().mockImplementation((dto) => dto),
      save: jest
        .fn()
        .mockImplementation((entity) => Promise.resolve({ ...entity, id: 1 })),
      findOne: jest.fn(),
      findAndCount: jest
        .fn()
        .mockResolvedValue([[{ id: 1, createdAt: new Date() }], 1]),
    };
    mockTicketRepo = {
      update: jest.fn(),
    };

    const module: TestingModule = await Test.createTestingModule({
      providers: [
        ChatService,
        { provide: getRepositoryToken(Message), useValue: mockMessageRepo },
        { provide: getRepositoryToken(Ticket), useValue: mockTicketRepo },
        {
          provide: SearchService,
          useValue: { indexMessage: jest.fn().mockResolvedValue(true) },
        },
        { provide: FilesService, useValue: {} },
      ],
    }).compile();

    service = module.get<ChatService>(ChatService);
  });

  describe('createMessage', () => {
    it('should create message and return it', async () => {
      mockMessageRepo.findOne.mockResolvedValue({
        id: 1,
        content: 'test',
        type: 'text',
      });
      const data = {
        ticketId: 1,
        senderId: 1,
        content: 'test',
        type: 'text' as any,
      };
      const result = await service.createMessage(data);
      expect(result).toHaveProperty('id', 1);
      expect(mockMessageRepo.save).toHaveBeenCalled();
    });
  });

  describe('recallMessage', () => {
    it('should recall message successfully', async () => {
      const tenMinsAgo = new Date(Date.now() - 5 * 60 * 1000);
      mockMessageRepo.findOne.mockResolvedValue({
        id: 1,
        senderId: 1,
        ticketId: 1,
        type: 'text',
        content: 'old',
        createdAt: tenMinsAgo,
      });

      await service.recallMessage(1, 1, 'admin');

      expect(mockMessageRepo.save).toHaveBeenCalledWith(
        expect.objectContaining({
          content: expect.stringContaining('已被撤回'),
          isRecalled: true,
        }),
      );
    });

    it('should throw if message not found', async () => {
      mockMessageRepo.findOne.mockResolvedValue(null);
      await expect(service.recallMessage(1, 1, 'admin')).rejects.toThrow(
        NotFoundException,
      );
    });

    it('should throw if wrong sender', async () => {
      mockMessageRepo.findOne.mockResolvedValue({
        id: 1,
        senderId: 2,
        ticketId: 1,
        type: 'text',
        content: 'old',
        createdAt: new Date(),
      });
      await expect(service.recallMessage(1, 1, 'admin')).rejects.toThrow(
        ForbiddenException,
      );
    });
  });

  describe('getMessagesByTicket', () => {
    it('should get messages by ticket', async () => {
      const result = await service.getMessagesByTicket(1);
      expect(result.items).toHaveLength(1);
      expect(mockMessageRepo.findAndCount).toHaveBeenCalled();
    });
  });
});

import {
  Injectable,
  ForbiddenException,
  NotFoundException,
  BadRequestException,
  Logger,
} from '@nestjs/common';
import { InjectRepository } from '@nestjs/typeorm';
import { Repository } from 'typeorm';
import { Message, MessageType } from '../../entities/message.entity';
import { SearchService } from '../search/search.service';
import { FilesService } from '../files/files.service';

@Injectable()
export class ChatService {
  private readonly logger = new Logger(ChatService.name);

  constructor(
    @InjectRepository(Message)
    private readonly messageRepository: Repository<Message>,
    private readonly searchService: SearchService,
    private readonly filesService: FilesService,
  ) {}

  async createMessage(data: {
    ticketId: number;
    senderId: number | null;
    senderName?: string;
    content: string;
    type?: MessageType;
    fileUrl?: string;
    fileName?: string;
    fileSize?: number;
  }): Promise<Message> {
    const message = this.messageRepository.create(data);
    const saved = await this.messageRepository.save(message);

    // 重新查询以获取关联的发送者信息
    const fullMessage = (await this.messageRepository.findOne({
      where: { id: saved.id },
      relations: ['sender'],
    })) as Message;

    // 显式同步到 Elasticsearch（不依赖 Subscriber）
    if (fullMessage) {
      this.searchService.indexMessage(fullMessage).catch((e) => {
        this.logger.warn(
          `ES sync failed for message #${fullMessage.id}: ${e.message}`,
        );
      });
    }

    return fullMessage;
  }

  async recallMessage(
    messageId: number,
    userId: number | string,
    username?: string,
  ): Promise<Message> {
    const message = await this.messageRepository.findOne({
      where: { id: messageId },
      relations: ['sender'],
    });
    if (!message) throw new NotFoundException('消息不存在');

    // 权限校验
    if (typeof userId === 'string' && userId.startsWith('ext-')) {
      if (message.senderId !== null || message.senderName !== username) {
        throw new ForbiddenException('只能撤回自己的消息');
      }
    } else {
      if (message.senderId !== Number(userId)) {
        throw new ForbiddenException('只能撤回自己的消息');
      }
    }
    if (message.isRecalled) throw new BadRequestException('消息已被撤回');

    // 检查 10 分钟时间窗口
    const elapsed = Date.now() - new Date(message.createdAt).getTime();
    if (elapsed > 10 * 60 * 1000) {
      throw new BadRequestException('只能撤回 10 分钟内的消息');
    }

    // 删除云端文件
    if (
      message.fileUrl &&
      (message.type === MessageType.IMAGE || message.type === MessageType.FILE)
    ) {
      try {
        const filename = message.fileUrl.split('/').pop();
        if (filename) {
          // 这里使用不等待的异步调用或等待都可
          this.filesService.deleteFromCos(filename).catch((err) => {
            this.logger.error('Delete recalled file from COS failed:', err);
          });
        }
      } catch (err) {
        this.logger.error('Delete recalled file failed:', err);
      }
    }

    message.isRecalled = true;
    message.content = '该消息已被撤回';
    message.fileUrl = '';
    message.fileName = '';
    message.fileSize = 0;
    return this.messageRepository.save(message);
  }

  async getMessagesByTicket(ticketId: number, page = 1, pageSize = 200) {
    const [messages, total] = await this.messageRepository.findAndCount({
      where: { ticketId },
      relations: ['sender'],
      order: { createdAt: 'DESC' },
      skip: (page - 1) * pageSize,
      take: pageSize,
    });

    messages.reverse();

    return {
      items: messages.map((msg) => ({
        id: msg.id,
        content: msg.content,
        type: msg.type,
        fileUrl: msg.isRecalled ? null : msg.fileUrl,
        fileName: msg.isRecalled ? null : msg.fileName,
        fileSize: msg.isRecalled ? null : msg.fileSize,
        senderName: msg.senderName,
        isRecalled: msg.isRecalled || false,
        createdAt: msg.createdAt,
        sender: msg.sender
          ? {
              id: msg.sender.id,
              username: msg.sender.username,
              displayName: msg.sender.displayName,
              realName: msg.sender.realName,
              avatar: msg.sender.avatar,
            }
          : null,
      })),
      total,
    };
  }
}

import { RoomService, RoomUserInfo } from './room.service';
import { Ticket, TicketStatus } from '../../entities/ticket.entity';

describe('RoomService', () => {
  let service: RoomService;

  beforeEach(() => {
    service = new RoomService();
  });

  // ── Helper: 构造 Ticket mock ──
  const makeTicket = (overrides: Partial<Ticket> = {}): Ticket =>
    ({
      id: 1,
      creatorId: 10,
      assigneeId: 20,
      participants: [{ id: 30 }],
      status: TicketStatus.IN_PROGRESS,
      isRoomLocked: false,
      isExternalLinkDisabled: false,
      ...overrides,
    }) as unknown as Ticket;

  // ══════════════════════════════════════════════
  //  在线用户映射
  // ══════════════════════════════════════════════

  describe('onlineUsers', () => {
    it('should track add / get / remove', () => {
      service.addOnlineUser(1, 'socket-abc');
      expect(service.getSocketId(1)).toBe('socket-abc');

      service.removeOnlineUser(1);
      expect(service.getSocketId(1)).toBeUndefined();
    });

    it('should handle string userId', () => {
      service.addOnlineUser('ext-99', 'socket-xyz');
      expect(service.getSocketId('ext-99')).toBe('socket-xyz');
    });
  });

  // ══════════════════════════════════════════════
  //  isAuthorizedForRoom (锁定房间权限)
  // ══════════════════════════════════════════════

  describe('isAuthorizedForRoom', () => {
    it('should allow admin regardless', () => {
      const user: RoomUserInfo = { userId: 99, role: 'admin' };
      expect(service.isAuthorizedForRoom(user, makeTicket())).toBe(true);
    });

    it('should allow external user with matching ticketId and link enabled', () => {
      const user: RoomUserInfo = {
        userId: 99,
        role: 'external',
        allowedTicketId: 1,
      };
      expect(service.isAuthorizedForRoom(user, makeTicket())).toBe(true);
    });

    it('should deny external user if link is disabled', () => {
      const user: RoomUserInfo = {
        userId: 99,
        role: 'external',
        allowedTicketId: 1,
      };
      expect(
        service.isAuthorizedForRoom(
          user,
          makeTicket({ isExternalLinkDisabled: true }),
        ),
      ).toBe(false);
    });

    it('should deny external user with wrong ticketId', () => {
      const user: RoomUserInfo = {
        userId: 99,
        role: 'external',
        allowedTicketId: 999,
      };
      expect(service.isAuthorizedForRoom(user, makeTicket())).toBe(false);
    });

    it('should allow ticket creator', () => {
      const user: RoomUserInfo = { userId: 10, role: 'user' };
      expect(service.isAuthorizedForRoom(user, makeTicket())).toBe(true);
    });

    it('should allow ticket assignee', () => {
      const user: RoomUserInfo = { userId: 20, role: 'user' };
      expect(service.isAuthorizedForRoom(user, makeTicket())).toBe(true);
    });

    it('should allow ticket participant', () => {
      const user: RoomUserInfo = { userId: 30, role: 'user' };
      expect(service.isAuthorizedForRoom(user, makeTicket())).toBe(true);
    });

    it('should deny unrelated user', () => {
      const user: RoomUserInfo = { userId: 999, role: 'user' };
      expect(service.isAuthorizedForRoom(user, makeTicket())).toBe(false);
    });
  });

  // ══════════════════════════════════════════════
  //  canAccessTicketRoom (工单聊天室访问)
  // ══════════════════════════════════════════════

  describe('canAccessTicketRoom', () => {
    it('should allow admin', () => {
      const user: RoomUserInfo = { userId: 99, role: 'admin' };
      expect(service.canAccessTicketRoom(user, makeTicket())).toBe(true);
    });

    it('should allow ticket member even if room is locked', () => {
      const user: RoomUserInfo = { userId: 10, role: 'user' };
      expect(
        service.canAccessTicketRoom(user, makeTicket({ isRoomLocked: true })),
      ).toBe(true);
    });

    it('should deny non-member if room is locked', () => {
      const user: RoomUserInfo = { userId: 999, role: 'user' };
      expect(
        service.canAccessTicketRoom(user, makeTicket({ isRoomLocked: true })),
      ).toBe(false);
    });

    it('should allow non-member to unlocked in_progress room', () => {
      const user: RoomUserInfo = { userId: 999, role: 'user' };
      expect(service.canAccessTicketRoom(user, makeTicket())).toBe(true);
    });

    it('should deny non-member to directed pending ticket (has assignee)', () => {
      const user: RoomUserInfo = { userId: 999, role: 'user' };
      const ticket = makeTicket({
        status: TicketStatus.PENDING,
        assigneeId: 20, // directed
      });
      expect(service.canAccessTicketRoom(user, ticket)).toBe(false);
    });

    it('should allow non-member to undirected pending ticket (no assignee)', () => {
      const user: RoomUserInfo = { userId: 999, role: 'user' };
      const ticket = makeTicket({
        status: TicketStatus.PENDING,
        assigneeId: null as any, // undirected
      });
      expect(service.canAccessTicketRoom(user, ticket)).toBe(true);
    });

    it('should deny external user with disabled link', () => {
      const user: RoomUserInfo = {
        userId: 99,
        role: 'external',
        allowedTicketId: 1,
      };
      expect(
        service.canAccessTicketRoom(
          user,
          makeTicket({ isExternalLinkDisabled: true }),
        ),
      ).toBe(false);
    });

    it('should allow external user with valid link', () => {
      const user: RoomUserInfo = {
        userId: 99,
        role: 'external',
        allowedTicketId: 1,
      };
      expect(service.canAccessTicketRoom(user, makeTicket())).toBe(true);
    });
  });
});

import {
  Injectable,
  BadRequestException,
  NotFoundException,
} from '@nestjs/common';
import { InjectRepository } from '@nestjs/typeorm';
import { Repository } from 'typeorm';
import { Ticket, TicketStatus, TicketType } from '../../entities/ticket.entity';
import { User } from '../../entities/user.entity';
import { IsString, IsNotEmpty, IsOptional } from 'class-validator';

export class PushTicketDto {
  @IsString()
  @IsNotEmpty()
  title: string;

  @IsString()
  @IsNotEmpty()
  description: string;

  @IsString()
  @IsNotEmpty()
  serviceNo: string;

  @IsString()
  @IsNotEmpty()
  customerName: string;

  @IsString()
  @IsNotEmpty()
  creatorEmployeeId: string;

  @IsString()
  @IsNotEmpty()
  assigneeEmployeeId: string;

  @IsString()
  @IsOptional()
  type?: string;

  @IsString()
  @IsOptional()
  category1?: string;

  @IsString()
  @IsOptional()
  category2?: string;

  @IsString()
  @IsOptional()
  category3?: string;

  @IsString()
  @IsOptional()
  status?: string;
}

@Injectable()
export class ExtTicketsService {
  constructor(
    @InjectRepository(Ticket)
    private readonly ticketRepository: Repository<Ticket>,
    @InjectRepository(User)
    private readonly userRepository: Repository<User>,
  ) {}

  async createTicketFromOMM(dto: PushTicketDto) {
    if (
      !dto.title ||
      !dto.description ||
      !dto.serviceNo ||
      !dto.creatorEmployeeId ||
      !dto.assigneeEmployeeId
    ) {
      throw new BadRequestException('Missing required fields');
    }

    // Lookup users by employeeId
    const creator = await this.userRepository.findOne({
      where: { employeeId: dto.creatorEmployeeId },
    });
    if (!creator) {
      throw new BadRequestException(
        `Creator with employeeId ${dto.creatorEmployeeId} not found`,
      );
    }

    const assignee = await this.userRepository.findOne({
      where: { employeeId: dto.assigneeEmployeeId },
    });
    if (!assignee) {
      throw new BadRequestException(
        `Assignee with employeeId ${dto.assigneeEmployeeId} not found`,
      );
    }

    // Check for duplicate serviceNo (UPSERT logic)
    const existingTicket = await this.ticketRepository.findOne({
      where: { serviceNo: dto.serviceNo },
      relations: ['participants'],
    });

    if (existingTicket) {
      // Update existing ticket
      let changed = false;
      if (dto.title && existingTicket.title !== dto.title) {
        existingTicket.title = dto.title;
        changed = true;
      }
      if (dto.description && existingTicket.description !== dto.description) {
        existingTicket.description = dto.description;
        changed = true;
      }
      if (
        dto.customerName &&
        existingTicket.customerName !== dto.customerName
      ) {
        existingTicket.customerName = dto.customerName;
        changed = true;
      }
      if (dto.type && existingTicket.type !== dto.type) {
        existingTicket.type = dto.type as TicketType;
        changed = true;
      }
      if (dto.category1 && existingTicket.category1 !== dto.category1) {
        existingTicket.category1 = dto.category1;
        changed = true;
      }
      if (dto.category2 && existingTicket.category2 !== dto.category2) {
        existingTicket.category2 = dto.category2;
        changed = true;
      }
      if (dto.category3 && existingTicket.category3 !== dto.category3) {
        existingTicket.category3 = dto.category3;
        changed = true;
      }

      // Update Creator
      if (existingTicket.creatorId !== creator.id) {
        existingTicket.creatorId = creator.id;
        if (!existingTicket.participants.some((p) => p.id === creator.id)) {
          existingTicket.participants.push(creator);
        }
        changed = true;
      }

      // Update Assignee
      if (existingTicket.assigneeId !== assignee.id) {
        existingTicket.assigneeId = assignee.id;

        // Ensure new assignee is in participants
        if (!existingTicket.participants.some((p) => p.id === assignee.id)) {
          existingTicket.participants.push(assignee);
        }
        changed = true;
      }

      // Update status if provided and valid
      if (
        dto.status &&
        Object.values(TicketStatus).includes(dto.status as TicketStatus)
      ) {
        if (existingTicket.status !== dto.status) {
          existingTicket.status = dto.status as TicketStatus;
          changed = true;
        }
      }

      let savedTicket = existingTicket;
      if (changed) {
        savedTicket = await this.ticketRepository.save(existingTicket);
      }

      return {
        id: savedTicket.id,
        ticketNo: savedTicket.ticketNo,
        title: savedTicket.title,
        status: savedTicket.status,
        serviceNo: savedTicket.serviceNo,
        customerName: savedTicket.customerName,
        createdAt: savedTicket.createdAt,
        updated: changed,
      };
    }

    // Generate ticket number (TK + YYYYMMDD + sequence)
    const dateStr = new Date().toISOString().slice(0, 10).replace(/-/g, '');
    const ticketNo = `TK${dateStr}${Math.floor(1000 + Math.random() * 9000)}`;

    const newTicket = this.ticketRepository.create({
      ticketNo,
      title: dto.title,
      description: dto.description,
      serviceNo: dto.serviceNo,
      customerName: dto.customerName,
      creatorId: creator.id,
      assigneeId: assignee.id,
      status: TicketStatus.IN_PROGRESS,
      type: (dto.type as TicketType) || TicketType.OTHER,
      category1: dto.category1,
      category2: dto.category2,
      category3: dto.category3,
      participants: [creator, assignee],
    });

    const savedTicket = await this.ticketRepository.save(newTicket);

    return {
      id: savedTicket.id,
      ticketNo: savedTicket.ticketNo,
      title: savedTicket.title,
      status: savedTicket.status,
      serviceNo: savedTicket.serviceNo,
      customerName: savedTicket.customerName,
      createdAt: savedTicket.createdAt,
      updated: false,
    };
  }

  async getTicketStatus(serviceNo: string) {
    const ticket = await this.ticketRepository.findOne({
      where: { serviceNo },
      relations: ['assignee'],
    });

    if (!ticket) {
      throw new NotFoundException(
        `Ticket with serviceNo ${serviceNo} not found`,
      );
    }

    return {
      id: ticket.id,
      ticketNo: ticket.ticketNo,
      serviceNo: ticket.serviceNo,
      status: ticket.status,
      assignee: ticket.assignee
        ? {
            realName: ticket.assignee.realName,
            employeeId: ticket.assignee.employeeId,
          }
        : null,
      createdAt: ticket.createdAt,
      assignedAt: ticket.assignedAt,
    };
  }
}

