      expect(result.data.workerUpdated).toBe(false);
    });
  });
});

import {
  Controller,
  Get,
  Post,
  Body,
  UseGuards,
  UseInterceptors,
  UploadedFile,
  UsePipes,
  ValidationPipe,
  Logger,
} from '@nestjs/common';
import { FileInterceptor } from '@nestjs/platform-express';
import { diskStorage } from 'multer';
import { extname, join } from 'path';
import { existsSync, mkdirSync } from 'fs';
import { AuthGuard } from '@nestjs/passport';
import { PermissionsGuard } from '../auth/permissions.guard';
import {
  AllowExternalAccess,
  Permissions,
} from '../auth/permissions.decorator';
import { SettingsService } from './settings.service';
import { ConfigService } from '@nestjs/config';
import axios from 'axios';

// 确保上传目录存在
const uploadDir = join(process.cwd(), 'uploads', 'logo');
if (!existsSync(uploadDir)) mkdirSync(uploadDir, { recursive: true });

@Controller('settings')
@UseGuards(AuthGuard('jwt'), PermissionsGuard)
@UsePipes(
  new ValidationPipe({
    whitelist: false,
    forbidNonWhitelisted: false,
    transform: true,
  }),
)
export class SettingsController {
  private readonly logger = new Logger(SettingsController.name);

  constructor(
    private readonly settingsService: SettingsService,
    private readonly configService: ConfigService,
  ) {}

  /** 获取所有系统配置 */
  @Get()
  @Permissions('settings:read', 'settings:edit') // Allow read or manage to view
  async getAll() {
    const data = await this.settingsService.getAll();
    return { code: 0, data };
  }

  /** 保存 AI 模型配置 */
  @Post('ai')
  @Permissions('settings:edit')
  async saveAi(
    @Body()
    body: {
      visionModel?: string;
      visionApiKey?: string;
      systemPrompt?: string;
      imageModel?: string;
      imageApiKey?: string;
      chatModel?: string;
      chatApiKey?: string;
    },
  ) {
    await this.settingsService.saveMany({
      'ai.visionModel': body.visionModel || '',
      'ai.visionApiKey': body.visionApiKey || '',
      'ai.systemPrompt': body.systemPrompt || '',
      'ai.imageModel': body.imageModel || '',
      'ai.imageApiKey': body.imageApiKey || '',
      'ai.chatModel': body.chatModel || '',
      'ai.chatApiKey': body.chatApiKey || '',
    });
    return { code: 0, message: 'AI 模型配置保存成功' };
  }

  /** 保存企业信息 */
  @Post('biz')
  @Permissions('settings:edit')
  async saveBiz(
    @Body()
    body: {
      companyName?: string;
      websiteUrl?: string;
      companyEmail?: string;
      companyPhone?: string;
      sla?: string;
    },
  ) {
    await this.settingsService.saveMany({
      'biz.companyName': body.companyName || '',
      'biz.websiteUrl': body.websiteUrl || '',
      'biz.companyEmail': body.companyEmail || '',
      'biz.companyPhone': body.companyPhone || '',
      'biz.sla': body.sla || '',
    });
    return { code: 0, message: '企业信息保存成功' };
  }

  /** 上传 Logo */
  @Post('logo')
  @Permissions('settings:edit')
  @UseInterceptors(
    FileInterceptor('file', {
      storage: diskStorage({
        destination: uploadDir,
        filename: (_req, _file, cb) => {
          // 始终保存为 logo.xxx，覆盖旧文件
          const ext = extname(_file.originalname);
          cb(null, `logo${ext}`);
        },
      }),
      fileFilter: (_req, file, cb) => {
        if (!file.mimetype.startsWith('image/')) {
          return cb(new Error('仅允许上传图片文件'), false);
        }
        cb(null, true);
      },
      limits: { fileSize: 5 * 1024 * 1024 }, // 5MB
    }),
  )
  async uploadLogo(@UploadedFile() file: Express.Multer.File) {
    if (!file) return { code: -1, message: '文件上传失败' };
    const logoUrl = `/uploads/logo/${file.filename}`;
    await this.settingsService.set('biz.logoUrl', logoUrl);
    return { code: 0, message: 'Logo 上传成功', data: { logoUrl } };
  }

  /** 保存安全设置 */
  @Post('security')
  @Permissions('settings:edit')
  async saveSecurity(@Body() body: { shareExpiration?: string }) {
    await this.settingsService.saveMany({
      'security.shareExpiration': body.shareExpiration || '7d',
    });
    return { code: 0, message: '安全设置保存成功' };
  }

  /** 获取 WebRTC 配置 (供前端直调) */
  @Get('webrtc-config')
  @AllowExternalAccess('webrtc')
  async getWebRtcConfig() {
    const data = await this.settingsService.getAll();
    const mode = data['webrtc.mode'] || 'auto';

    if (mode === 'auto') {
      // 返回国内可用的免费高可用 STUN
      return {
        code: 0,
        data: [
          { urls: 'stun:stun.qq.com:3478' },
          { urls: 'stun:stun.miwifi.com:3478' },
          { urls: 'stun:stun.chat.bilibili.com:3478' },
        ],
      };
    } else {
      // 返回自定义配置
      const iceServers: any[] = [];
      const customStun = data['webrtc.customStun'];
      const customTurn = data['webrtc.customTurn'];

      if (customStun) {
        iceServers.push({ urls: `stun:${customStun}` });
      }
      if (customTurn) {
        iceServers.push({
          urls: `turn:${customTurn}`,
          username: data['webrtc.turnUsername'] || '',
          credential: data['webrtc.turnPassword'] || '',
        });
      }

      // Fallback 机制：如果什么都没配，给一个保底的
      if (iceServers.length === 0) {
        iceServers.push({ urls: 'stun:stun.qq.com:3478' });
      }
      return { code: 0, data: iceServers };
    }
  }

  /** 保存 WebRTC 设置 */
  @Post('webrtc')
  @Permissions('settings:edit')
  async saveWebRtc(
    @Body()
    body: {
      mode?: string;
      customStun?: string;
      customTurn?: string;
      turnUsername?: string;
      turnPassword?: string;
      screenShareMaxViewers?: number;
      voiceMaxParticipants?: number;
    },
  ) {
    await this.settingsService.saveMany({
      'webrtc.mode': body.mode || 'auto',
      'webrtc.customStun': body.customStun || '',
      'webrtc.customTurn': body.customTurn || '',
      'webrtc.turnUsername': body.turnUsername || '',
      'webrtc.turnPassword': body.turnPassword || '',
    });

    // 保存人数限制（如果提供了）
    if (body.screenShareMaxViewers !== undefined) {
      await this.settingsService.set(
        'screenShare_maxViewers',
        String(body.screenShareMaxViewers),
      );
    }
    if (body.voiceMaxParticipants !== undefined) {
      await this.settingsService.set(
        'voice_maxParticipants',
        String(body.voiceMaxParticipants),
      );
    }

    return { code: 0, message: 'WebRTC 配置保存成功' };
  }

  /** 保存存储配置 */
  @Post('storage')
  @Permissions('settings:edit')
  async saveStorage(
    @Body()
    body: {
      provider?: string;
      cosSecretId?: string;
      cosSecretKey?: string;
      cosBucket?: string;
      cosRegion?: string;
      s3Endpoint?: string;
      s3AccessKey?: string;
      s3SecretKey?: string;
      s3Bucket?: string;
      s3Region?: string;
    },
  ) {
    const toSave: Record<string, string> = {
      'storage.provider': body.provider || 'local',
      'storage.cos.secretId': body.cosSecretId || '',
      'storage.cos.bucket': body.cosBucket || '',
      'storage.cos.region': body.cosRegion || '',
      'storage.s3.endpoint': body.s3Endpoint || '',
      'storage.s3.accessKey': body.s3AccessKey || '',
      'storage.s3.bucket': body.s3Bucket || '',
      'storage.s3.region': body.s3Region || '',
    };

    // 只有非空时才覆盖 SecretKey（前端传空字符串表示不修改密码）
    if (body.cosSecretKey && body.cosSecretKey.trim() !== '') {
      toSave['storage.cos.secretKey'] = body.cosSecretKey;
    }
    if (body.s3SecretKey && body.s3SecretKey.trim() !== '') {
      toSave['storage.s3.secretKey'] = body.s3SecretKey;
    }

    await this.settingsService.saveMany(toSave);
    return { code: 0, message: '存储配置保存成功' };
  }

  /** 获取 AI 协作配置（直接从 Worker 读，确保所有后端显示一致） */
  @Get('codex')
  @Permissions('settings:read', 'settings:manage')
  async getCodexConfig() {
    const workerUrl = this.configService.get<string>(
      'CODEX_WORKER_URL',
      'http://43.130.240.106:3100',
    );
    const apiKey = this.configService.get<string>('CODEX_WORKER_API_KEY', '');
    try {
      const res = await axios.get(`${workerUrl}/api/config`, {
        timeout: 4000,
        headers: apiKey ? { 'X-API-Key': apiKey } : {},
      });
      return { code: 0, data: res.data?.data ?? res.data };
    } catch (err: any) {
      // 回退到本地 DB 值
      this.logger.warn(
        `Worker unreachable, falling back to DB: ${err.message}`,
      );
      const d = await this.settingsService.getAll();
      return {
        code: 0,
        data: {
          maxRetries: parseInt(d['codex.maxRetries'] ?? '3', 10),
          concurrency: parseInt(d['codex.concurrency'] ?? '2', 10),
        },
      };
    }
  }

  /** 保存 AI 协作配置 */
  @Post('codex')
  @Permissions('settings:edit')
  async saveCodexConfig(
    @Body()
    body: {
      concurrency?: number;
      maxResumeAttempts?: number;
      cosSecretId?: string;
      cosSecretKey?: string;
      cosBucket?: string;
      cosRegion?: string;
      storageProvider?: string;
      s3Endpoint?: string;
      s3AccessKey?: string;
      s3SecretKey?: string;
      s3Bucket?: string;
      s3Region?: string;
    },
  ) {
    const concurrency = body.concurrency ?? 2;
    const maxResumeAttempts = body.maxResumeAttempts;

    // Save to DB
    await this.settingsService.saveMany({
      'codex.concurrency': String(concurrency),
      ...(maxResumeAttempts !== undefined
        ? { 'codex.maxResumeAttempts': String(maxResumeAttempts) }
        : {}),
    });

    // Push config to Worker
    const workerUrl = this.configService.get<string>(
      'CODEX_WORKER_URL',
      'http://43.130.240.106:3100',
    );
    const apiKey = this.configService.get<string>('CODEX_WORKER_API_KEY', '');
    let workerUpdated = false;

    try {
      await axios.post(
        `${workerUrl}/api/config`,
        {
          concurrency,
          maxResumeAttempts,
          cosSecretId: body.cosSecretId,
          cosSecretKey: body.cosSecretKey,
          cosBucket: body.cosBucket,
          cosRegion: body.cosRegion,
          storageProvider: body.storageProvider,
          s3Endpoint: body.s3Endpoint,
          s3AccessKey: body.s3AccessKey,
          s3SecretKey: body.s3SecretKey,
          s3Bucket: body.s3Bucket,
          s3Region: body.s3Region,
        },
        {
          timeout: 5000,
          headers: apiKey ? { 'X-API-Key': apiKey } : {},
        },
      );
      workerUpdated = true;
      this.logger.log(
        `Pushed concurrency=${concurrency}, maxResumeAttempts=${maxResumeAttempts} to Worker`,
      );
    } catch (err: any) {
      this.logger.warn(`Failed to push config to Worker: ${err.message}`);
    }

    return {
      code: 0,
      message: 'AI 协作配置已保存',
      data: {
        concurrency,
        workerUpdated,
        restartRequired: false,
        note: workerUpdated
          ? '✅ 系统配置已写入 Worker .env，Worker 将在 2 秒后自动重启生效'
          : '✅ 配置已提交，但未能推送到 Worker（请检查连接）',
      },
    };
  }
}

