    it('should deny non-assignee', async () => {
      (service.findOne as jest.Mock).mockResolvedValue({
        id: 1,
        status: TicketStatus.IN_PROGRESS,
        assigneeId: 20,
      });
      await expect(service.requestClose(1, 99)).rejects.toThrow(
